+    #[test]
+    fn test_concurrent_begin_rebases_execution_image_to_opened_pager_visibility() {
+        let _serial = super::fsqlite_core_test_serializer();
+        let dir = tempfile::tempdir().unwrap();
+        let path = dir.path().join("begin_opened_pager_visibility_rebase.db");
+        let path_str = path.to_str().unwrap();
+
+        let conn_a = Connection::open(path_str).unwrap();
+        conn_a
+            .execute("CREATE TABLE t (id INTEGER PRIMARY KEY, v INTEGER NOT NULL);")
+            .unwrap();
+        conn_a.execute("INSERT INTO t VALUES (1, 0);").unwrap();
+
+        let conn_b = Connection::open(path_str).unwrap();
+        assert_eq!(
+            conn_b
+                .query_row("SELECT v FROM t WHERE id = 1;")
+                .unwrap()
+                .values()[0],
+            SqliteValue::Integer(0),
+            "seed read should populate conn_b's execution image before conn_a advances it"
+        );
+
+        conn_a.execute("UPDATE t SET v = 1 WHERE id = 1;").unwrap();
+
+        let cx = conn_b.op_cx().unwrap();
+        let mut txn = conn_b
+            .begin_pager_txn_with_busy_timeout(
+                &conn_b.pager,
+                &cx,
+                TransactionMode::Concurrent,
+                true,
+            )
+            .unwrap();
+        let opened_visible_commit_seq = txn
+            .published_visible_commit_seq_hint()
+            .expect("opened pager transaction should expose its bound visibility");
+        assert!(
+            opened_visible_commit_seq > *conn_b.memdb_visible_commit_seq.borrow(),
+            "test precondition: conn_b execution image should be stale before rebase"
+        );
+
+        let mut stale_snapshot = Snapshot::new(
+            CommitSeq::ZERO,
+            SchemaEpoch::new((*conn_b.schema_cookie.borrow()).into()),
+        );
+        conn_b
+            .refresh_concurrent_begin_from_open_txn(&cx, &mut txn, &mut stale_snapshot)
+            .unwrap();
+
+        assert_eq!(
+            stale_snapshot.high, opened_visible_commit_seq,
+            "concurrent BEGIN should rebase the MVCC snapshot to the opened pager view"
+        );
+        assert_eq!(
+            *conn_b.memdb_visible_commit_seq.borrow(),
+            opened_visible_commit_seq,
+            "concurrent BEGIN should reload the execution image to the opened pager view"
+        );
+
+        txn.rollback(&cx).unwrap();
+    }
